// Times sets number of times SyncRepo.ResolveConflict should be invoked
func (mmResolveConflict *mSyncRepoMockResolveConflict) Times(n uint64) *mSyncRepoMockResolveConflict {
	if n == 0 {
		mmResolveConflict.mock.t.Fatalf("Times of SyncRepoMock.ResolveConflict mock can not be zero")
	}
	mm_atomic.StoreUint64(&mmResolveConflict.expectedInvocations, n)
	mmResolveConflict.expectedInvocationsOrigin = minimock.CallerInfo(1)
	return mmResolveConflict
}

func (mmResolveConflict *mSyncRepoMockResolveConflict) invocationsDone() bool {
	if len(mmResolveConflict.expectations) == 0 && mmResolveConflict.defaultExpectation == nil && mmResolveConflict.mock.funcResolveConflict == nil {
		return true
	}

	totalInvocations := mm_atomic.LoadUint64(&mmResolveConflict.mock.afterResolveConflictCounter)
	expectedInvocations := mm_atomic.LoadUint64(&mmResolveConflict.expectedInvocations)

	return totalInvocations > 0 && (expectedInvocations == 0 || expectedInvocations == totalInvocations)
}

// ResolveConflict implements mm_sync.SyncRepo
func (mmResolveConflict *SyncRepoMock) ResolveConflict(conflictID int64, resolution string) (err error) {
	mm_atomic.AddUint64(&mmResolveConflict.beforeResolveConflictCounter, 1)
	defer mm_atomic.AddUint64(&mmResolveConflict.afterResolveConflictCounter, 1)

	mmResolveConflict.t.Helper()

	if mmResolveConflict.inspectFuncResolveConflict != nil {
		mmResolveConflict.inspectFuncResolveConflict(conflictID, resolution)
	}

	mm_params := SyncRepoMockResolveConflictParams{conflictID, resolution}

	// Record call args
	mmResolveConflict.ResolveConflictMock.mutex.Lock()
	mmResolveConflict.ResolveConflictMock.callArgs = append(mmResolveConflict.ResolveConflictMock.callArgs, &mm_params)
	mmResolveConflict.ResolveConflictMock.mutex.Unlock()

	for _, e := range mmResolveConflict.ResolveConflictMock.expectations {
		if minimock.Equal(*e.params, mm_params) {
			mm_atomic.AddUint64(&e.Counter, 1)
			return e.results.err
		}
	}

	if mmResolveConflict.ResolveConflictMock.defaultExpectation != nil {
		mm_atomic.AddUint64(&mmResolveConflict.ResolveConflictMock.defaultExpectation.Counter, 1)
		mm_want := mmResolveConflict.ResolveConflictMock.defaultExpectation.params
		mm_want_ptrs := mmResolveConflict.ResolveConflictMock.defaultExpectation.paramPtrs

		mm_got := SyncRepoMockResolveConflictParams{conflictID, resolution}

		if mm_want_ptrs != nil {

			if mm_want_ptrs.conflictID != nil && !minimock.Equal(*mm_want_ptrs.conflictID, mm_got.conflictID) {
				mmResolveConflict.t.Errorf("SyncRepoMock.ResolveConflict got unexpected parameter conflictID, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
					mmResolveConflict.ResolveConflictMock.defaultExpectation.expectationOrigins.originConflictID, *mm_want_ptrs.conflictID, mm_got.conflictID, minimock.Diff(*mm_want_ptrs.conflictID, mm_got.conflictID))
			}

			if mm_want_ptrs.resolution != nil && !minimock.Equal(*mm_want_ptrs.resolution, mm_got.resolution) {
				mmResolveConflict.t.Errorf("SyncRepoMock.ResolveConflict got unexpected parameter resolution, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
					mmResolveConflict.ResolveConflictMock.defaultExpectation.expectationOrigins.originResolution, *mm_want_ptrs.resolution, mm_got.resolution, minimock.Diff(*mm_want_ptrs.resolution, mm_got.resolution))
			}

		} else if mm_want != nil && !minimock.Equal(*mm_want, mm_got) {
			mmResolveConflict.t.Errorf("SyncRepoMock.ResolveConflict got unexpected parameters, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
				mmResolveConflict.ResolveConflictMock.defaultExpectation.expectationOrigins.origin, *mm_want, mm_got, minimock.Diff(*mm_want, mm_got))
		}

		mm_results := mmResolveConflict.ResolveConflictMock.defaultExpectation.results
		if mm_results == nil {
			mmResolveConflict.t.Fatal("No results are set for the SyncRepoMock.ResolveConflict")
		}
		return (*mm_results).err
	}
	if mmResolveConflict.funcResolveConflict != nil {
		return mmResolveConflict.funcResolveConflict(conflictID, resolution)
	}
	mmResolveConflict.t.Fatalf("Unexpected call to SyncRepoMock.ResolveConflict. %v %v", conflictID, resolution)
	return
}

// ResolveConflictAfterCounter returns a count of finished SyncRepoMock.ResolveConflict invocations
func (mmResolveConflict *SyncRepoMock) ResolveConflictAfterCounter() uint64 {
	return mm_atomic.LoadUint64(&mmResolveConflict.afterResolveConflictCounter)
}

// ResolveConflictBeforeCounter returns a count of SyncRepoMock.ResolveConflict invocations
func (mmResolveConflict *SyncRepoMock) ResolveConflictBeforeCounter() uint64 {
	return mm_atomic.LoadUint64(&mmResolveConflict.beforeResolveConflictCounter)
}

// Calls returns a list of arguments used in each call to SyncRepoMock.ResolveConflict.
// The list is in the same order as the calls were made (i.e. recent calls have a higher index)
func (mmResolveConflict *mSyncRepoMockResolveConflict) Calls() []*SyncRepoMockResolveConflictParams {
	mmResolveConflict.mutex.RLock()

	argCopy := make([]*SyncRepoMockResolveConflictParams, len(mmResolveConflict.callArgs))
	copy(argCopy, mmResolveConflict.callArgs)

	mmResolveConflict.mutex.RUnlock()

	return argCopy
}

// MinimockResolveConflictDone returns true if the count of the ResolveConflict invocations corresponds
// the number of defined expectations
func (m *SyncRepoMock) MinimockResolveConflictDone() bool {
	if m.ResolveConflictMock.optional {
		// Optional methods provide '0 or more' call count restriction.
		return true
	}

	for _, e := range m.ResolveConflictMock.expectations {
		if mm_atomic.LoadUint64(&e.Counter) < 1 {
			return false
		}
	}

	return m.ResolveConflictMock.invocationsDone()
}

// MinimockResolveConflictInspect logs each unmet expectation
func (m *SyncRepoMock) MinimockResolveConflictInspect() {
	for _, e := range m.ResolveConflictMock.expectations {
		if mm_atomic.LoadUint64(&e.Counter) < 1 {
			m.t.Errorf("Expected call to SyncRepoMock.ResolveConflict at\n%s with params: %#v", e.expectationOrigins.origin, *e.params)
		}
	}

	afterResolveConflictCounter := mm_atomic.LoadUint64(&m.afterResolveConflictCounter)
	// if default expectation was set then invocations count should be greater than zero
	if m.ResolveConflictMock.defaultExpectation != nil && afterResolveConflictCounter < 1 {
		if m.ResolveConflictMock.defaultExpectation.params == nil {
			m.t.Errorf("Expected call to SyncRepoMock.ResolveConflict at\n%s", m.ResolveConflictMock.defaultExpectation.returnOrigin)
		} else {
			m.t.Errorf("Expected call to SyncRepoMock.ResolveConflict at\n%s with params: %#v", m.ResolveConflictMock.defaultExpectation.expectationOrigins.origin, *m.ResolveConflictMock.defaultExpectation.params)
		}
	}
	// if func was set then invocations count should be greater than zero
	if m.funcResolveConflict != nil && afterResolveConflictCounter < 1 {
		m.t.Errorf("Expected call to SyncRepoMock.ResolveConflict at\n%s", m.funcResolveConflictOrigin)
	}

	if !m.ResolveConflictMock.invocationsDone() && afterResolveConflictCounter > 0 {
		m.t.Errorf("Expected %d calls to SyncRepoMock.ResolveConflict at\n%s but found %d calls",
			mm_atomic.LoadUint64(&m.ResolveConflictMock.expectedInvocations), m.ResolveConflictMock.expectedInvocationsOrigin, afterResolveConflictCounter)
	}
}

// MinimockFinish checks that all mocked methods have been called the expected number of times
func (m *SyncRepoMock) MinimockFinish() {
	m.finishOnce.Do(func() {
		if !m.minimockDone() {
			m.MinimockCreateConflictInspect()

			m.MinimockCreateRevisionInspect()

			m.MinimockGetConflictsInspect()

			m.MinimockGetMaxRevisionInspect()

			m.MinimockGetRevisionsInspect()

			m.MinimockResolveConflictInspect()
		}
	})
}

// MinimockWait waits for all mocked methods to be called the expected number of times
func (m *SyncRepoMock) MinimockWait(timeout mm_time.Duration) {
	timeoutCh := mm_time.After(timeout)
	for {
		if m.minimockDone() {
			return
		}
		select {
		case <-timeoutCh:
			m.MinimockFinish()
			return
		case <-mm_time.After(10 * mm_time.Millisecond):
		}
	}
}

func (m *SyncRepoMock) minimockDone() bool {
	done := true
	return done &&
		m.MinimockCreateConflictDone() &&
		m.MinimockCreateRevisionDone() &&
		m.MinimockGetConflictsDone() &&
		m.MinimockGetMaxRevisionDone() &&
		m.MinimockGetRevisionsDone() &&
		m.MinimockResolveConflictDone()
}
